import React from "react";
import { graphql } from "gatsby";
import Layout from "../components/layout";
import Seo from "../components/seo";
import PostList from "../components/post-list";
import Pagination from "../components/pagination-new";
import CategoryButtons from "../components/category-buttons";

const CategoryTemplate = ({ data, pageContext }) => {
  const { category, currentPage, numPages } = pageContext;
  const posts = data.allMarkdownRemark.edges;
  const categories = ["All", ...data.categories.group.map(group => group.fieldValue)];
  const currentPath = typeof window !== "undefined" ? window.location.pathname : "";

  return (
    <Layout>
      <Seo title={`Posts in ${category} - Page ${currentPage}`} />
        <div className="category-page">
          <div className="container">
            <h1>Posts in category: {category}</h1>
            <CategoryButtons categories={categories} />
            <PostList posts={posts} currentPath={currentPath} />
            <Pagination currentPage={currentPage} numberOfPages={numPages} basePath={`/category/${category}`} />
          </div>
        </div>

    </Layout>
  );
};

export const query = graphql`
  query($category: String!) {
    allMarkdownRemark(
      filter: {frontmatter: {category: {eq: $category}}}
      sort: {frontmatter: {date: DESC}}
    ) {
      edges {
        node {
          frontmatter {
            title
            date(formatString: "YYYY/MM/DD")
            slug
            excerpt
            category
            image {
              childImageSharp {
                gatsbyImageData(layout: FULL_WIDTH)
              }
            }
          }
          rawMarkdownBody
        }
      }
    }
    categories: allMarkdownRemark {
      group(field: {frontmatter: {category: SELECT}}) {
        fieldValue
      }
    }
  }
`;

export default CategoryTemplate;
